+    while written < buf.len() {
+        let n = std::future::poll_fn(|cx| {
+            std::pin::Pin::new(&mut *stream).poll_write(cx, &buf[written..])
+        })
+        .await?;
+        if n == 0 {
+            return Err(std::io::Error::new(
+                std::io::ErrorKind::WriteZero,
+                "connection closed",
+            ));
+        }
+        written += n;
+    }
+    Ok(())
+}
